urlset:
{%- for entry in entries %}
  {%- if not entry.permalink is containing("/tags/")
      and not entry.permalink is containing("/blog/archive/")
      and not entry.permalink is containing("/blog/page/1/") %}

    {{ entry.permalink | safe }}
    {%- set_global english_url = entry.permalink %}
    {%- set_global chinese_url = false %}
    {%- if entry.permalink is containing("/zh/") %}
      {%- set_global english_url = entry.permalink | replace(from="/zh/", to="/") %}
      {%- set_global chinese_url = entry.permalink %}
    {%- else %}
      {%- for candidate in entries %}
        {%- if candidate.permalink is containing("/zh/") %}
          {%- set candidate_default = candidate.permalink | replace(from="/zh/", to="/") %}
          {%- if candidate_default == entry.permalink %}{% set_global chinese_url = candidate.permalink %}{% endif %}
        {%- endif %}
      {%- endfor %}
    {%- endif %}
    {%- if chinese_url %}



    {%- endif %}
    {%- if entry.updated %}
    {{ entry.updated }}
    {%- endif %}

  {%- endif %}
{%- endfor %}
